sp_widget.client_script:
api.controller = function() {
	var c = this;
	c.status = sessionStorage.getItem('status');

	/* ================= REFRESH ================= */
	c.refreshData = function() {
		c.server.update();
	};

	/* ================= TABS ================= */
	c.tabs = ["All", "Success", "Failed", "Partial"];
	c.activeTab = "All";

	/* ================= SET TAB ================= */
	c.setTab = function(tab) {
		c.activeTab = tab;
	};

	/* ================= FILTER RECORDS ================= */
	c.getFilteredRecords = function() {

		if (c.activeTab === "All") {
			return c.data.records;
		}

		if (c.activeTab === "Success") {
			return c.data.records.filter(function(rec) {
				return rec.status === 'success';
			});
		}

		if (c.activeTab === "Failed") {
			return c.data.records.filter(function(rec) {
				return rec.status === 'failed';
			});
		}

		if (c.activeTab === "Partial") {
			return c.data.records.filter(function(rec) {
				//var rate = parseInt(rec.success_rate, 10);
				//return rate > 0 && rate < 100;
				return rec.status === 'partial';
			});
		}
		//console.log("data.records = " + JSON.stringify(c.data.records));
		return c.data.records;
	};
	/* ================= COUNT ================= */
	c.getCount = function(tab) {
		if (tab === "All") {
			return c.data.totalRecords;
		}
		if(tab == "Success") {
			return c.data.successRecords;
		}
		if(tab == "Failed") {
			return c.data.failedRecords;
		}
		if(tab == "Partial") {
			return c.data.partialRecords;
		}
	};

	/* ================= SVG PROGRESS RING ================= */
	setTimeout(function () {

		var total = c.data.totalRecords || 1;
		var success = c.data.successRecords || 0;

		var percent = (success / total) * 100;

		var circle = document.getElementById("progressBar");

		if (!circle) return;

		var radius = 70;
		var circumference = 2 * Math.PI * radius;

		// Start empty
		circle.style.strokeDasharray = circumference;
		circle.style.strokeDashoffset = circumference;

		// Force reflow (important for animation)
		circle.getBoundingClientRect();

		var offset = circumference - (percent / 100) * circumference;

		// Animate
		circle.style.strokeDashoffset = offset;

	}, 150);

	/* ================= MODAL ================= */
	c.showModal = false;
	c.selectedRecord = {};

	c.openModal = function(rec) {

		c.selectedRecord = angular.copy(rec);

		console.log(
			'Selected Record',
			c.selectedRecord
		);

		c.showModal = true;
	};

	c.closeModal = function() {
		c.showModal = false;
	};	
};

sp_widget.css:
/* ===== MAIN LAYOUT ===== */
.sp-layout {
  display: flex;
  min-height: 100vh;
  background: #f3f6f9;
}

/* Sidebar width */
.sidebar-area {
  flex-basis: 260px;
  flex-shrink:0;
  height:100%;
}

/* CONTENT */
.content-area {
  flex: 1;
  padding: 20px 30px;
}

/* ================= HERO ================= */
.mic-hero {
  display: flex;
  justify-content: space-between;
  padding: 56px 48px;
  border-radius: 18px;
  color: #1e293b;
  background: linear-gradient(135deg, #dce8ff 0%, #e8eeff 40%, #c8d9f9 70%, #b8ccf8 100%);
  min-height: 280px;
}
.mic-badge {
  display: inline-block;
  padding: 6px 12px;
  border-radius: 999px;
  background: rgba(255,255,255,0.75);
  border: 1.5px solid rgba(17,106,248,0.2);
  font-size: 12px;
  color: #1e293b;
  margin-bottom: 12px;
}
.mic-hero h1 {
  font-size: 28px;
  margin: 6px 0;
  font-weight: 700;
  color: #0f172a;
}
.mic-hero h1 span {
  color: #116AF8;
}
.mic-hero p {
  font-size: 14px;
  color: #334155;
  opacity: 1;
  max-width: 520px;
}
.mic-breadcrumb {
  margin-top: 12px;
  font-size: 13px;
  opacity: 0.8;
}
.mic-hero-right {
  display: flex;
  gap: 10px;
  align-items: flex-start;
}

/* ================= BUTTONS ================= */
.btn {
  border: none;
  padding: 10px 16px;
  border-radius: 8px;
  cursor: pointer;
  font-size: 13px;
}

.btn.primary {
  background: #06b6d4;
  color: #fff;
}

.btn.ghost {
  background: rgba(255,255,255,0.12);
  color: #fff;
}

.btn.small {
  padding: 6px 12px;
  font-size: 12px;
}


/* ================= CARD ================= */
.mic-card {
  background: #f8fafc;
  border-radius: 18px;
  padding: 24px;
  box-shadow: 0 10px 30px rgba(0,0,0,0.06);
}

/* ================= HEADER ================= */
.mic-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.mic-header .left {
  display: flex;
  align-items: center;
  gap: 14px;
}



.mic-header h2 {
  margin: 0;
  font-size: 20px;
}

/* TAGS */
.tags {
  margin-top: 6px;
}

.tag {
  font-size: 11px;
  padding: 4px 10px;
  border-radius: 999px;
  margin-right: 6px;
}

.tag.success {
  background: #dcfce7;
  color: #16a34a;
}

.tag.failed {
  background: #fee2e2;
  color: #dc2626;
}

.tag.partial {
  background: #fef3c7;
  color: #d97706;
}

/*.tag.warn {
  background: #ffedd5;
  color: #ea580c;
}*/

/* ================= STATS ================= */
.mic-stats {
  display: flex;
  gap: 16px;
  margin: 24px 0;
}

.stat {
  flex: 1;
  padding: 18px 20px;
  border-radius: 14px;
  border: 1.5px solid;
  background: linear-gradient(135deg, rgba(255,255,255,0.7), rgba(255,255,255,0.4));
  backdrop-filter: blur(6px);
  transition: all 0.2s ease;
}

.stat span {
  font-size: 13px;
  font-weight: 500;
  display: block;
  margin-bottom: 6px;
}

.stat h3 {
  font-size: 26px;
  font-weight: 700;
  margin: 0;
}

/* COLORS */
.stat.blue {
  border-color: #7dd3fc;
  background: linear-gradient(135deg, #e0f2fe, #f0f9ff);
}
.stat.blue span { color: #0284c7; }
.stat.blue h3 { color: #075985; }

.stat.green {
  border-color: #86efac;
  background: linear-gradient(135deg, #dcfce7, #f0fdf4);
}
.stat.green span { color: #16a34a; }
.stat.green h3 { color: #065f46; }

.stat.red {
  border-color: #fca5a5;
  background: linear-gradient(135deg, #fee2e2, #fff1f2);
}
.stat.red span { color: #dc2626; }
.stat.red h3 { color: #7f1d1d; }

.stat.orange {
  border-color: #fdba74;
  background: linear-gradient(135deg, #ffedd5, #fff7ed);
}
.stat.orange span { color: #ea580c; }
.stat.orange h3 { color: #7c2d12; }

.stat:hover {
  transform: translateY(-2px);
  box-shadow: 0 6px 18px rgba(0,0,0,0.08);
}

/* ================= DIVIDER ================= */
.mic-card hr {
  border: none;
  border-top: 1px solid #e2e8f0;
  margin: 18px 0;
}

/* ================= DETAILS ================= */
.mic-details-box {
  margin-top: 10px;
  padding: 18px 20px;
  border: 1px solid #e2e8f0; /* light grey border */
  border-radius: 14px;
  background: #f9fbfd; /* subtle light background */
}

/* keep your existing mic-details */
.mic-details {
  display: flex;
  justify-content: space-between;
  font-size: 13px;
  color: #334155;
}

.mic-details .col {
  display: flex;
  flex-direction: column;
  gap: 14px;
}
.mic-details b {
  font-weight: 600;
}

/* PILLS */
.pill {
  display: inline-block;
  background: #e0f2fe;
  color: #0284c7;
  padding: 4px 10px;
  border-radius: 999px;
  margin-right: 6px;
  font-size: 11px;
}

/* ================= PROGRESS ================= */
.mic-progress {
  margin-top: 34px;
  display: flex;
  justify-content: center;
}

/* wrapper */
.progress-wrap {
  position: relative;
  width: 160px;
  height: 160px;
}

/* rotate svg */
.progress-wrap svg {
  transform: rotate(-90deg);
}

/* background circle */
.progress-wrap circle:first-child {
  fill: none;
  stroke: #e5e7eb;
  stroke-width: 10;
}

/* animated circle */
#progressBar {
  fill: none;
  stroke: #06b6d4;
  stroke-width: 10;
  stroke-linecap: round;

  transition: stroke-dashoffset 1.4s ease-in-out;

  /* glow */
  filter: drop-shadow(0 0 6px rgba(6,182,212,0.4));
}

/* center text */
.progress-text {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);

  font-size: 18px;
  font-weight: 600;
  color: #1e293b;
}

// Table records
/* ================= RECORDS CARD ================= */
.records-card {
  margin-top: 30px;
  background: #f8fafc;
  border-radius: 18px;
  padding: 20px;
  box-shadow: 0 8px 25px rgba(0,0,0,0.05);
}

/* HEADER */
.records-header h3 {
  margin: 0;
  font-size: 18px;
}

.records-header p {
  margin: 4px 0 16px;
  font-size: 13px;
  color: #64748b;
}

/* ================= TABS ================= */
.records-tabs {
  display: flex;
  background: #e5e7eb;
  border-radius: 999px;
  padding: 4px;
  margin-bottom: 18px;
}

.tab {
  flex: 1;
  text-align: center;
  padding: 8px;
  border-radius: 999px;
  font-size: 13px;
  cursor: pointer;
}

.tab.active {
  background: #fff;
  font-weight: 600;
  box-shadow: 0 2px 6px rgba(0,0,0,0.08);
}

/* ================= TABLE ================= */
.records-table {
  width: 100%;
}

/* HEADER ROW */
.table-head {
  display: grid;
  grid-template-columns: 1.2fr 1fr 2fr 1fr 1fr;
  font-size: 12px;
  color: #64748b;
  padding: 10px 0;
  border-bottom: 1px solid #e2e8f0;
}

/* ROW */
.table-row {
  display: grid;
  grid-template-columns: 1.2fr 1fr 2fr 1fr 1fr;
  padding: 14px 0;
  border-bottom: 1px solid #f1f5f9;
  align-items: center;
  font-size: 13px;
}

.table-row:last-child {
  border-bottom: none;
}

.bold {
  font-weight: 600;
}

/* ================= STATUS ================= */
.status {
  padding: 4px 10px;
  border-radius: 999px;
  font-size: 11px;
}

.status.success {
  background: #dcfce7;
  color: #16a34a;
}

.status.failed {
  background: #fee2e2;
  color: #dc2626;
}

.status.skipped {
  background: #e2e8f0;
  color: #475569;
}

/* ================= ACTION ================= */
.action {
  color: #0284c7;
  cursor: pointer;
  font-weight: 500;
}

.retry {
  color: #ea580c;
  margin-left: 10px;
}

/* ================= MODAL ================= */
.mic-modal {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  z-index: 999;
}

.mic-modal-overlay {
  position: absolute;
  width: 100%;
  height: 100%;
  background: rgba(15, 23, 42, 0.6);
  backdrop-filter: blur(4px);
}

.mic-modal-box {
  position: relative;
  width: 900px;
  max-width: 90%;
  margin: 60px auto;
  background: #f8fafc;
  border-radius: 16px;
  padding: 20px;
  z-index: 1000;
  box-shadow: 0 20px 50px rgba(0,0,0,0.2);
}

.modal-close {
  position: absolute;
  top: 12px;
  right: 14px;
  border: none;
  background: transparent;
  font-size: 18px;
  cursor: pointer;
  color: #64748b;
}

.modal-close:hover {
  color: #0f172a;
}

/* HEADER */
.mic-modal-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

/* DETAILS GRID */
.mic-modal-details {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 14px;
  margin-top: 20px;
}

.mic-modal-details .box {
  background: #fff;
  border: 1px solid #e2e8f0;
  padding: 12px;
  border-radius: 10px;
}

.mic-modal-details span {
  font-size: 11px;
  color: #64748b;
}

.mic-modal-details p {
  margin: 4px 0 0;
  font-weight: 500;
}

/* LOGS */
.mic-modal-logs {
  margin-top: 20px;
}

.log-box {
  background: #0f172a;
  color: #22c55e;
  padding: 14px;
  border-radius: 10px;
  font-size: 12px;
  max-height: 200px;
  overflow: auto;
}
/* migration modal */
.status-icon {
  width: 64px;
  height: 64px;
  border-radius: 16px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 28px;
  background-color: white;
  font-weight: bold;
}

.status-icon.success {
  background: #2EAA32;
}

.status-icon.partial {
  background: #f59e0b;
}

.status-icon.failed {
  background: #ef4444;
}



.error-box {
  margin-top: 20px;
  border-radius: 16px;
  padding: 20px;
  display: flex;
  align-items: flex-start;
  gap: 15px;
}

.error-box.failed {
  background: #fef2f2;
  border: 1px solid #fecaca;
}

.error-box.partial {
  background: #fffbeb;
  border: 1px solid #fde68a;
}

.error-icon {
  width: 40px;
  height: 40px;
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  font-weight: bold;
}

.error-box.failed .error-icon {
  background: #ef4444;
}

.error-box.partial .error-icon {
  background: #f59e0b;
}

sp_widget.script:
(function() {

	data.side = $sp.getWidget('tracenow_sidebar');

	//data.total = 247;
	data.successRecords = 0;
	data.failed = 0;
	data.skipped = 0;
	data.records = [];
	data.tables = [];
	data.all_records = [];
	data.migration_id = $sp.getParameter('migration_id');
	var totalCount = 0, insertedCount = 0, updatedCount = 0, successCount = 0, failedCount = 0, partialCount = 0, table = '', tar_rec_number;
	//console.log('migration_id = ' + data.migration_id);


	//get migration data from table
	var gr = new GlideRecordSecure('x_sysus_tracenow_migration_details');
	gr.addQuery('sys_created_by', gs.getUserName());
	gr.addQuery('number', data.migration_id);
	gr.query();

	var migrationSysId = '';

	if (gr.next()) {

		migrationSysId = gr.getUniqueValue();

		data.targetInstance = gr.getValue('target_instance');
		data.source_instance = gr.getValue('instance_url');
		data.duration = gr.getValue('duration');
		data.completedAt = gr.getValue('sys_updated_on');
		data.current_user = gr.getDisplayValue('sys_created_by');
		data.targetInstance = gr.getValue('target_instance');
		data.source_instance = gr.getValue('instance_url');
		data.duration = gr.getValue('duration');
		data.completedAt = gr.getValue('sys_updated_on');
		data.current_user = gr.getDisplayValue('sys_created_by');
	}
	data.totalRecords = totalCount;
	data.successRecords = successCount;
	data.failedRecords = failedCount;
	data.partialRecords = partialCount;
	//console.log('data.all_records = ' + JSON.stringify(data.all_records));
	var logGR = new GlideRecordSecure('x_sysus_tracenow_tracenow_migration_record_log'); // <-- your record log table

	logGR.addQuery('migration', migrationSysId);
	logGR.orderBy('sys_created_on');
	logGR.query();

	while (logGR.next()) {

		//query the record number in target instance for the migrated record
		var tbl_gr = new GlideRecordSecure(logGR.getValue('table'));
		tbl_gr.addQuery('sys_id', logGR.getValue('source_sys_id'));
		tbl_gr.query();
		while(tbl_gr.next()) {
			tar_rec_number = tbl_gr.getValue('number');
		}

		data.records.push({

			table: logGR.getValue('table') || '',
			target_rec_number: tar_rec_number || '',
			source_id: logGR.getValue('source_sys_id') || '',
			source_rec_number: logGR.getValue('record_number') || '',
			short_description: logGR.getValue('short_description') || '',
			state: logGR.getDisplayValue('state') || '',

			status: (logGR.getValue('status') || '').toLowerCase(),

			action: logGR.getValue('action') || '',

			reason: logGR.getValue('reason') || '',

			duration: logGR.getValue('duration') || '',

			logs: JSON.parse(
				logGR.getValue('migration_log') || '{"logs":[]}'
			)

		});
	}


	//console.log('records = ' + JSON.stringify(data.records));

	//status logic for the top
	data.totalRecords = data.records.length;

	data.successRecords = data.records.filter(function(r) {
		return r.status === 'success';
	}).length;

	data.failedRecords = data.records.filter(function(r) {
		return r.status === 'failed';
	}).length;

	data.partialRecords = data.records.filter(function(r) {
		return r.status === 'partial';
	}).length;
})();
